const issues = $input.all();
const inProgress = issues.filter(i => i.json.fields.status.name === 'In Progress');
const inReview = issues.filter(i => i.json.fields.status.name === 'In Review');
const done = issues.filter(i => i.json.fields.status.name === 'Done');
const todo = issues.filter(i => i.json.fields.status.name === 'To Do');

const formatList = (list) => list.length === 0
  ? `<p style="color:#888;margin:4px 0;">None</p>`
  : list.map(i => `<p style="margin:4px 0;">• <strong>${i.json.key}</strong>: ${i.json.fields.summary}</p>`).join('');

const section = (emoji, title, color, count, list) => `
  <div style="margin-bottom:24px;">
    <div style="background:${color};padding:8px 14px;border-radius:6px;display:inline-block;margin-bottom:8px;">
      <strong style="color:white;">${emoji} ${title} (${count})</strong>
    </div>
    <div style="padding-left:8px;">${formatList(list)}</div>
  </div>`;

const digest = `
<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:24px;">
  <h2 style="border-bottom:2px solid #eee;padding-bottom:12px;color:#1a1a1a;">
    📋 Daily Jira Digest
  </h2>
  <p style="color:#555;margin-bottom:24px;">
    📅 ${new Date().toDateString()} &nbsp;|&nbsp; Project: <strong>WhatToCookApp</strong>
  </p>

  ${section('🔨', 'In Progress', '#0052cc', inProgress.length, inProgress)}
  ${section('🔁', 'In Review', '#6554c0', inReview.length, inReview)}
  ${section('✅', 'Done', '#00875a', done.length, done)}
  ${section('📋', 'To Do', '#505f79', todo.length, todo)}

  <p style="color:#aaa;font-size:12px;border-top:1px solid #eee;padding-top:12px;margin-top:8px;">
    Sent automatically via n8n
  </p>
</div>`;

return [{ json: { 
  digest,
  subject: "Daily Jira Digest - " + new Date().toDateString()
}}];
